{"command": "python3 << 'PYEOF'
import yaml

with open('/root/.hermes/config.yaml') as f:
    c = yaml.safe_load(f)

# Add new MCP servers
c.setdefault('mcp_servers', {})
new_mcps = {
    'postgres': {
        'command': 'npx',
        'args': ['-y', '@modelcontextprotocol/server-postgres'],
        'enabled': False,
        'tools': {'resources': False, 'prompts': False}
    },
    'sqlite': {
        'command': 'npx',
        'args': ['-y', '@modelcontextprotocol/server-sqlite'],
        'enabled': False,
        'tools': {'resources': False, 'prompts': False}
    },
    'puppeteer': {
        'command': 'npx',
        'args': ['-y', '@modelcontextprotocol/server-puppeteer'],
        'enabled': False,
        'tools': {'resources': False, 'prompts': False}
    },
    'memory-server': {
        'command': 'npx',
        'args': ['-y', '@modelcontextprotocol/server-memory'],
        'enabled': False,
        'tools': {'resources': False, 'prompts': False}
    },
    'google-drive': {
        'command': 'npx',
        'args': ['-y', '@modelcontextprotocol/server-google-drive'],
        'enabled': False,
        'tools': {'resources': False, 'prompts': False}
    },
    'slack': {
        'command': 'npx',
        'args': ['-y', '@modelcontextprotocol/server-slack'],
        'enabled': False,
        'tools': {'resources': False, 'prompts': False}
    },
}
for name, cfg in new_mcps.items():
    if name not in c['mcp_servers']:
        c['mcp_servers'][name] = cfg

# Add scoped access to existing MCPs (OnlyTerp pattern)
for srv in ['github', 'filesystem', 'cloudflare', 'supabase', 'stripe']:
    if srv in c['mcp_servers'] and isinstance(c['mcp_servers'][srv], dict):
        c['mcp_servers'][srv].setdefault('tools', {})
        if isinstance(c['mcp_servers'][srv]['tools'], dict):
            c['mcp_servers'][srv]['tools'].setdefault('resources', False)
            c['mcp_servers'][srv]['tools'].setdefault('prompts', False)

# Add HMC config
c.setdefault('hermes_context_manager', {
    'enabled': True,
    'max_context_percent': 0.80,
    'dashboard_port': 0,
    'dedup_enabled': True,
    'error_purge_enabled': True,
    'code_filter_enabled': True,
})

# Enable plugin if not already
c.setdefault('plugins', {'enabled': [], 'disabled': []})
if 'hermes-context-manager' not in c['plugins'].get('enabled', []):
    c['plugins']['enabled'].append('hermes-context-manager')

# Add memory provider
c.setdefault('memory', {})['provider'] = 'hindsight'

# Add curator config
c.setdefault('curator', {'enabled': True, 'interval_hours': 168, 'min_idle_hours': 2,
    'stale_after_days': 30, 'archive_after_days': 90})

# Write back
with open('/root/.hermes/config.yaml', 'w') as f:
    yaml.dump(c, f, default_flow_style=False, sort_keys=False, width=4096, indent=2)

print("CONFIG_UPDATED")
PYEOF", "timeout": 15}

